function getLang(){return localStorage.getItem('wgLang')||'ru'}
async function setLang(lang){localStorage.setItem('wgLang',lang);closeModal();applyLang();if(typeof refreshAll==='function')await refreshAll();if(document.getElementById('screenSettings')?.classList.contains('active')){renderSettings()}toast(t('saved'))}
function t(key){return(I18N[getLang()]||I18N.ru)[key]||key}
function applyLang(){document.documentElement.lang=getLang();document.querySelectorAll('[data-i18n]').forEach(el=>{el.textContent=t(el.dataset.i18n)})}

// ── helpers ──
function getToken(){return localStorage.getItem('wgApiToken')||''}
function setToken(v){localStorage.setItem('wgApiToken',v||'')}
function esc(s){return String(s??'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;').replaceAll('`','&#96;')}function escapeAttr(s){return String(s).replaceAll('&','&amp;').replaceAll("'",'\\\'').replaceAll('"','&quot;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('`','&#96;').replaceAll('\n','\\n').replaceAll('\r','\\r')}
function toast(msg){const el=document.getElementById('toast');el.textContent=msg;el.style.display='block';clearTimeout(toast.t);toast.t=setTimeout(()=>el.style.display='none',4000)}
function tip(msg){const el=document.getElementById('modal'),mc=document.getElementById('modalContent');mc.innerHTML=`<div style="max-width:320px;padding-top:16px"><p style="font-size:16px;line-height:1.5;margin:0">${esc(msg)}</p></div>`;el.showModal();el.onclick=function(e){if(e.target===el){closeModal();el.onclick=null}}}
function humanBytes(n){n=Number(n)||0;if(n<0)return'0 B';const u=['B','KB','MB','GB','TB'];let i=0;while(n>=1024&&i<u.length-1){n/=1024;i++}return n.toFixed(i>0?1:0)+' '+u[i]}
function peerAvatar(p){const n=(p?.name||'').toLowerCase();if(n.includes('уль'))return'👧';if(n.includes('пап')||n.includes('vadim'))return'👨';if(n.includes('мам')||n.includes('lud'))return'👩';if(n.includes('роут')||n.includes('router'))return'📡';if(n.includes('phone')||n.includes('тел'))return'📱';if(n.includes('note')||n.includes('pc')||n.includes('book'))return'💻';return'👤'}
function statusClass(p){return!p.enabled?'disabled':(p.online?'online':'offline')}
function ruleFor(p){return state.rules[p.client_id]||{}}
function ruleDaily(rule){return rule.daily_bytes?humanBytes(rule.daily_bytes):t('noLimit')}
function ruleSchedule(rule){const s=rule.schedule||{};return s.enabled?`${s.start||'22:00'} – ${s.end||'07:00'}`:t('noLimit2')}
function ruleScheduleDays(rule){const s=rule.schedule||{};if(!s.enabled)return'';const names=[t('mon'),t('tue'),t('wed'),t('thu'),t('fri'),t('sat'),t('sun')];const days=(s.days&&s.days.length?s.days:[0,1,2,3,4,5,6]);return days.map(i=>names[i]).join(' ')}
I18N.en.mon='Mon';I18N.en.tue='Tue';I18N.en.wed='Wed';I18N.en.thu='Thu';I18N.en.fri='Fri';I18N.en.sat='Sat';I18N.en.sun='Sun';I18N.ru.mon='Пн';I18N.ru.tue='Вт';I18N.ru.wed='Ср';I18N.ru.thu='Чт';I18N.ru.fri='Пт';I18N.ru.sat='Сб';I18N.ru.sun='Вс'
function iconsForPeer(p){const r=ruleFor(p);let out='';if(!p.enabled)out+='⏻';if(r.speed_limit_rate)out+='🐢';if(r.daily_bytes)out+='◴';if(r.schedule?.enabled)out+='🌙';if(p.protected)out+='🔒';return out}
function timeAgo(ts){ts=Number(ts)||0;if(!ts)return t('never');const diff=Math.max(0,Math.floor(Date.now()/1000)-ts);if(diff<60)return t('secAgo').replace('{n}',diff);if(diff<3600)return t('minAgo').replace('{n}',Math.floor(diff/60));if(diff<86400)return t('hourAgo').replace('{n}',Math.floor(diff/3600));return t('dayAgo').replace('{n}',Math.floor(diff/86400))}

// ── API ──
async function api(path,options={}){const fail=new Error(t('connectionError'));let res;try{res=await Promise.race([fetch(path,{...options,cache:'no-cache',headers:{...(options.headers||{}),'X-API-Token':getToken()}}),new Promise((_,r)=>setTimeout(()=>r(fail),20000))]);if(res===fail)throw fail}catch(e){throw e instanceof Error?e:fail}if(!res.ok){if(res.status===401)showLoginOverlay();const body=await res.text();try{const j=JSON.parse(body);throw new Error(j.detail||body)}catch(e){if(e instanceof SyntaxError)throw new Error(t('serverError'));throw e}}return res}

// ── login ──
function showLoginOverlay(){document.getElementById('loginOverlay').style.display='flex'}
function hideLoginOverlay(){document.getElementById('loginOverlay').style.display='none'}
function saveLoginToken(){const v=document.getElementById('loginTokenInput')?.value.trim();if(!v)return toast(t('apiTokenMissing'));setToken(v);hideLoginOverlay();refreshAll()}
document.getElementById('loginTokenInput')?.addEventListener('keydown',function(e){if(e.key==='Enter')saveLoginToken()})

// ── navigation ──
function setScreen(id){document.querySelectorAll('.screen').forEach(x=>x.classList.remove('active'));document.getElementById(id).classList.add('active');document.getElementById('bottomNav').style.display=id.startsWith('screen')&&!['screenPeer','screenTraffic','screenLimits'].includes(id)?'flex':'none'}
function showMain(tab){state.currentTab=tab;document.querySelectorAll('.bottom-nav button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));if(tab==='home'){renderHome();setScreen('screenHome')}if(tab==='devices'){renderDevices();setScreen('screenDevices')}if(tab==='settings'){state.settingsPage='';renderSettings();setScreen('screenSettings')}}

// ── home ──
function shieldSVG(){return'<svg viewBox="0 0 64 64" width="42" height="42" xmlns="http://www.w3.org/2000/svg"><defs><linearGradient id="fg" x1="18" y1="18" x2="46" y2="48"><stop offset="0%" stop-color="#4ade80"/><stop offset="100%" stop-color="#16a34a"/></linearGradient></defs><path d="M32 8A24 24 0 0 1 56 32" fill="none" stroke="#22c55e" stroke-width="4" stroke-linecap="round"/><path d="M56 32A24 24 0 0 1 32 56" fill="none" stroke="#22c55e" stroke-width="4" stroke-linecap="round"/><path d="M32 56A24 24 0 0 1 8 32" fill="none" stroke="#22c55e" stroke-width="4" stroke-linecap="round"/><path d="M8 32A24 24 0 0 1 32 8" fill="none" stroke="#22c55e" stroke-width="4" stroke-linecap="round"/><circle cx="32" cy="8" r="4.5" fill="#0f172a" stroke="#4ade80" stroke-width="3"/><circle cx="56" cy="32" r="4.5" fill="#0f172a" stroke="#4ade80" stroke-width="3"/><circle cx="32" cy="56" r="4.5" fill="#0f172a" stroke="#4ade80" stroke-width="3"/><circle cx="8" cy="32" r="4.5" fill="#0f172a" stroke="#4ade80" stroke-width="3"/><path d="M20 31L32 20L44 31V47H35V38H29V47H20Z" fill="url(#fg)"/><rect x="27" y="32" width="5" height="5" rx="1" fill="#06120b"/><rect x="34" y="32" width="5" height="5" rx="1" fill="#06120b"/></svg>'}
function renderError(e){document.getElementById('screenHome').innerHTML=`<div class="page-head"><div class="brand">${shieldSVG()}FamilyNet</div></div><div class="card"><b>${t('connectionError')}</b><p class="muted">${esc(e.message)}</p><button class="primary-btn" onclick="showLoginOverlay()">${t('enterToken')}</button></div>`;setScreen('screenHome')}
