function getStatus(){const backup=state.backups?.latest;const totalBytes=state.dashboard?.wireguard?.vpn_today_bytes||0;const warnBytes=state.dashboard?.wireguard?.traffic_warn_bytes;if(!warnBytes||warnBytes<=0)return{warn:false,title:t('vpnWorking'),subtitle:t('allSystemsOk')};if(!backup)return{warn:false,title:t('vpnWorking'),subtitle:t('allSystemsOk')};if(!backup.exists)return{warn:true,title:t('vpnWorking'),subtitle:t('backupFailed')};if(backup.mtime&&Date.now()/1000-backup.mtime>3*86400)return{warn:true,title:t('vpnWorking'),subtitle:t('backupFailed')};if(totalBytes>warnBytes){const gb=Math.round(warnBytes/GB);return{warn:true,title:t('vpnWorking'),subtitle:t('highTraffic').replace('{gb}',gb)}}return{warn:false,title:t('vpnWorking'),subtitle:t('allSystemsOk')}}
function renderHome(){const d=state.dashboard||{},w=d.wireguard||{};const peers=state.peers||[];const online=peers.filter(p=>p.online&&p.enabled).sort((a,b)=>((b.today_rx_bytes||0)+(b.today_tx_bytes||0))-((a.today_rx_bytes||0)+(a.today_tx_bytes||0)));const latest=state.backups?.latest;const total=humanBytes(w.vpn_today_bytes||0);const todayRx=humanBytes(peers.reduce((s,p)=>s+(p.today_rx_bytes||0),0));const todayTx=humanBytes(peers.reduce((s,p)=>s+(p.today_tx_bytes||0),0));const s=getStatus();if(s.warn){const todayStr=new Date().toISOString().slice(0,10);if(!_getNotifications().some(n=>n.title===s.subtitle&&new Date(n.ts).toISOString().slice(0,10)===todayStr))_addNotification(s.subtitle,s.subtitle)}else{const list=_getNotifications();const clean=list.filter(n=>n.title!==t('backupFailed'));if(clean.length<list.length)localStorage.setItem('wgNotif',JSON.stringify(clean))}const top=w.top_user_now||{};const el=document.getElementById('screenHome');el.innerHTML=`
<div class="page-head" style="margin-bottom:36px"><div class="brand">${shieldSVG()}FamilyNet</div></div>
<div class="card status-card" style="position:relative;cursor:pointer" onclick="showMain('settings');showSettingsPage('diagnostics')"><div class="shield-wrap${s.warn?' warn':''}"><svg viewBox="0 0 128 128" width="76" height="76" xmlns="http://www.w3.org/2000/svg"><defs><linearGradient id="sg2" x1="24" y1="18" x2="104" y2="112"><stop offset="0%" stop-color="#9be66d"/><stop offset="100%" stop-color="#22c55e"/></linearGradient><linearGradient id="fg2" x1="42" y1="34" x2="82" y2="102"><stop offset="0%" stop-color="#0f172a"/><stop offset="100%" stop-color="#020617"/></linearGradient></defs><path d="M64 12C78 22 92 28 108 31V58C108 88 88 109 64 118C40 109 20 88 20 58V31C36 28 50 22 64 12Z" fill="url(#sg2)"/><path d="M64 24C76 32 88 37 99 39V59C99 82 84 100 64 108C44 100 29 82 29 59V39C40 37 52 32 64 24Z" fill="none" stroke="#14532d" stroke-width="5" opacity=".75"/><g fill="url(#fg2)" stroke="#4ade80" stroke-width="2" stroke-linejoin="round"><rect x="40" y="43" width="12" height="22" rx="5"/><rect x="52" y="39" width="12" height="26" rx="5"/><rect x="64" y="39" width="12" height="26" rx="5"/><rect x="76" y="43" width="12" height="22" rx="5"/><path d="M39 58H88V77C88 87 80 94 70 94H55C45 94 38 87 38 77V62C38 60 38 59 39 58Z"/><path d="M39 63C31 65 29 75 36 81L49 88C52 89 55 86 53 82L48 67C46 63 43 62 39 63Z"/><path d="M48 92H80L86 108H42Z"/></g><g stroke="#6ee7b7" stroke-width="2" opacity=".55" stroke-linecap="round"><line x1="52" y1="43" x2="52" y2="63"/><line x1="64" y1="41" x2="64" y2="63"/><line x1="76" y1="43" x2="76" y2="63"/><line x1="50" y1="99" x2="78" y2="99"/></g></svg></div><div><div class="status-title">${s.title}</div><div class="${s.warn?'yellow':'green'}">${s.subtitle}</div></div>${_unreadCount()?`<div class="bell-icon-wrap" onclick="event.stopPropagation();_showNotifications()">🔔<span class="bell-badge">${_unreadCount()}</span></div>`:''}</div>
<div class="card"><div class="row"><b>${t('online')}</b><span><b class="green" style="font-size:28px">${online.length}</b> <span class="muted">${t('outOf')} ${peers.length}</span></span></div><div class="aw"><div class="avatar-row">${online.map((p,i)=>{const n=(p.name||'').length>16?esc(p.name.slice(0,15)+'…'):esc(p.name);return`<div class="avatar-wrap" onclick="openPeer('${esc(p.client_id)}')"><svg viewBox="0 0 68 86" class="avatar-label-svg"><defs><path id="ap${i}" d="M 0,33 A 39,39 0 0,1 68,33" fill="none"/></defs><text><textPath href="#ap${i}" startOffset="50%" text-anchor="middle">${n}</textPath></text></svg><div class="avatar online">${getAvatarHtml(p)}</div></div>`}).join('')}</div>${online.length>4?`<div class="scroll-arrow" onclick="this.parentElement.querySelector('.avatar-row').scrollBy({left:200,behavior:'smooth'})">›</div>`:''}</div></div>
<div class="card" style="display:flex;justify-content:space-between;align-items:center;cursor:pointer" onclick="openGlobalTraffic()"><div><div>${t('totalTrafficToday')}</div><div class="big-number" style="margin:0">${esc(total)}</div></div><div class="traffic-split"><span class="blue">↓ ${esc(todayTx)}</span><span class="green">↑ ${esc(todayRx)}</span>${top.name?`<div class="muted" style="margin-top:4px;font-size:15px">👑 ${esc(top.name)}</div>`:''}</div></div>
<div class="card" style="cursor:pointer" onclick="showMain('settings');showSettingsPage('backups')"><div class="row"><div><div>${t('lastBackup')}</div><div class="muted" style="margin-top:8px">${latest?.mtime?new Date(latest.mtime*1000).toLocaleString(getLang()==='ru'?'ru-RU':'en-GB',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'}):t('noData')}</div><div class="green" style="margin-top:8px">${latest?.exists?t('success'):t('notFound')}</div></div><span class="chev">›</span></div></div>`}

// ── devices ──
function renderDevices(){const peers=[...state.peers].sort((a,b)=>(b.online&&b.enabled)-(a.online&&a.enabled)||(b.enabled-a.enabled)||((b.today_rx_bytes||0)+(b.today_tx_bytes||0))-((a.today_rx_bytes||0)+(a.today_tx_bytes||0)));document.getElementById('screenDevices').innerHTML=`<div class="page-head"><div class="title">${t('devices')}</div><button class="round-btn" onclick="showCreateClient()">+</button></div>${peers.map((p,i)=>`<div class="device-card ${statusClass(p)}" onclick="openPeer('${esc(p.client_id)}')"><div class="device-main"><div class="avatar ${!p.enabled?'disabled':(p.online?'online':'')}">${getAvatarHtml(p)}</div><div style="display:flex;align-items:center;gap:8px"><div class="device-name">${esc(p.name)}</div><div class="${p.enabled?'green':'muted'}" style="font-size:14px">${esc(p.today_total_human||humanBytes((p.today_rx_bytes||0)+(p.today_tx_bytes||0)))}</div></div><div class="device-icons">${iconsForPeer(p)}</div><div class="chev">›</div></div></div>`).join('')}`}
function findPeer(id){return state.peers.find(p=>String(p.client_id)===String(id))}
function openPeer(id){state.selectedPeer=findPeer(id);renderPeer();setScreen('screenPeer')}
function renderPeer(){const p=state.selectedPeer;if(!p)return showMain('devices');const r=ruleFor(p);const isXray=(state.dashboard?.variant)==='xray';document.getElementById('screenPeer').innerHTML=`
<div class="profile"><button class="back" onclick="showMain('devices')" style="margin:0 -6px 0 -4px;position:relative;z-index:2">‹</button><div class="avatar ${!p.enabled?'disabled':(p.online?'online':'')}" onclick="pickAvatar('${esc(p.client_id)}')">${getAvatarHtml(p)}</div><div><div class="profile-name" onclick="editPeerName('${esc(p.client_id)}','${escapeAttr(p.name)}')">${esc(p.name)}<span style="font-size:18px;margin-left:8px;cursor:pointer">✏️</span></div><div class="muted">${!p.enabled?t('disabled'):esc(timeAgo(p.latest_handshake))}<span style="margin-left:12px;padding:3px 10px;border-radius:100px;font-size:12px;font-weight:600;background:${p.role==='admin'?'var(--blue)':'var(--line)'};color:${p.role==='admin'?'#fff':'var(--muted)'}">${p.role==='admin'?t('admin'):t('user')}</span></div></div></div>
<div class="card" style="display:flex;align-items:center;gap:10px;padding:14px 17px;font-size:18px;font-weight:800"><span>${t('todayTraffic')}:</span><span>${esc(p.today_total_human||p.transfer_total_human||'0 Б')}</span></div>
<div class="card info-list"><div class="info-row"><div class="info-icon">🐢</div><div class="info-title">${t('speed')}</div><div class="info-value">${esc((r=>r.speed_limit_rate||t('noLimit'))(r))}</div></div><div class="info-row"><div class="info-icon">◴</div><div class="info-title">${t('dailyLimit')}</div><div class="info-value">${esc(ruleDaily(r))}</div></div><div class="info-row"><div class="info-icon">🌙</div><div style="flex:1"><div class="info-title">${t('schedule')}</div><div class="info-sub">${esc(ruleScheduleDays(r))}</div></div><div class="info-value">${esc(ruleSchedule(r))}</div></div><div class="info-row"><div class="info-icon">🔒</div><div class="info-title">${t('clientProtection2')}</div><div class="info-value green">${p.protected?t('enabled2'):t('disabled2')}</div></div></div>
<div class="card info-list"><div class="info-row nav-row" onclick="openTraffic()"><div class="info-icon">▥</div><div class="info-title">${t('trafficHistory2')}</div><div class="chev">›</div></div><div class="info-row nav-row" onclick="openLimits()"><div class="info-icon"><svg viewBox="0 0 24 24" width="22" height="22" style="vertical-align:middle"><path d="M12 2L3 7v6c0 5.25 9 9 9 9s9-3.75 9-9V7l-9-5z" fill="#1e8cff"/><path d="M12 4l7 4v5c0 4-7 7-7 7s-7-3-7-7V8l7-4z" fill="#0b141c"/><path d="M10.5 13.5l-2-2L7 13l3.5 3.5L17 10l-1.5-1.5-5 5z" fill="#1e8cff"/></svg></div><div class="info-title">${t('limitsAndProtection')}</div><div class="chev">›</div></div></div>
${isXray?`<div class="card"><div class="xray-protos"><span class="xray-proto-label">REALITY</span><button class="action-btn" onclick="showXrayQR('reality','${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">⌗</span>${t('qr2')}</button><button class="action-btn" onclick="downloadXrayConfig('reality','${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">▣</span>${t('config2')}</button></div><div class="xray-protos"><span class="xray-proto-label">XHTTP</span><button class="action-btn" onclick="showXrayQR('xhttp','${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">⌗</span>${t('qr2')}</button><button class="action-btn" onclick="downloadXrayConfig('xhttp','${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">▣</span>${t('config2')}</button></div><div class="xray-protos"><span class="xray-proto-label">WS</span><button class="action-btn" onclick="showXrayQR('ws','${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">⌗</span>${t('qr2')}</button><button class="action-btn" onclick="downloadXrayConfig('ws','${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">▣</span>${t('config2')}</button></div><div class="action-grid" style="margin-top:10px;border-top:1px solid var(--line);padding-top:10px">${p.enabled?`<button class="action-btn danger" onclick="disablePeer('${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">⏻</span>${t('disable')}</button>`:`<button class="action-btn green-btn" onclick="enablePeer('${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">⏻</span>${t('enable')}</button>`}</div></div>`:`<div class="action-grid"><button class="action-btn qr" onclick="showQR('${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">⌗</span>${t('qr2')}</button><button class="action-btn config" onclick="downloadConfig('${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">▣</span>${t('config2')}</button>${p.enabled?`<button class="action-btn danger" onclick="disablePeer('${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">⏻</span>${t('disable')}</button>`:`<button class="action-btn green-btn" onclick="enablePeer('${esc(p.client_id)}','${escapeAttr(p.name)}')"><span class="ico">⏻</span>${t('enable')}</button>`}</div>`}<div class="delete-peer-wrap"><button class="delete-peer-btn" onclick="deletePeer('${esc(p.client_id)}','${escapeAttr(p.name)}')">🗑 ${t('deletePeer')}</button></div>`}
function getAvatarHtml(p){const v=localStorage.getItem('avatar_'+p.client_id);if(v&&v.startsWith('data:image/'))return`<img src="${esc(v)}" style="width:100%;height:100%;object-fit:cover;border-radius:50%">`;return esc(v||peerAvatar(p))}
function pickAvatar(id){showModal(`<h3>${t('avatar')}</h3><div id="avatarGrid" style="display:grid;grid-template-columns:repeat(6,1fr);gap:4px;font-size:32px;text-align:center">${['👤','👨','👩','👧','👦','👶','👴','👵','🧑','👸','🤴','🧔','👷','💻','📱','🖥️','📺','📶','🎮','🐱','🐶','🐰','🐼','🦊','🐸','🐵','🐮','🐷','🦁','🦄'].map(e=>`<div class="nav-row" style="padding:4px;border-radius:8px" data-e="${e}">${e}</div>`).join('')}</div><div class="nav-row" style="padding:12px;margin-top:10px;text-align:center;border:1px dashed var(--line);border-radius:14px" onclick="document.getElementById('avatarFileInput').click()">📷 ${t('uploadPhoto')}</div><input id="avatarFileInput" type="file" accept="image/*" style="display:none">`);document.getElementById('avatarGrid').onclick=function(ev){const d=ev.target.closest('[data-e]');if(d){setAvatar(id,d.getAttribute('data-e'))}};document.getElementById('avatarFileInput').onchange=function(ev){const f=ev.target.files[0];if(!f)return;const r=new FileReader();r.onload=function(){showCropModal(id,r.result)};r.readAsDataURL(f)}}
function loadAvatarsFromServer(){try{api('/avatars').then(r=>r.json()).then(a=>{for(const[id,val]of Object.entries(a)){const k='avatar_'+id;if(!localStorage.getItem(k))localStorage.setItem(k,val)}})}catch(e){}}
async function compressDataUrl(d){return new Promise(r=>{if(!d.startsWith('data:image')||d.length<102400){r(d);return}const img=new Image();img.onload=function(){const max=200;let w=img.width,h=img.height;if(w>max||h>max){const s=Math.min(max/w,max/h);w*=s;h*=s}const c=document.createElement('canvas');c.width=w;c.height=h;c.getContext('2d').drawImage(img,0,0,w,h);r(c.toDataURL('image/jpeg',.8))};img.onerror=function(){r(d)};img.src=d})}async function syncAvatarsToServer(){try{const all={};for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i);if(k.startsWith('avatar_')){const v=await compressDataUrl(localStorage.getItem(k));localStorage.setItem(k,v);all[k.slice(7)]=v}}await api('/avatars',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(all)})}catch(e){}}
const cropState={x:0,y:0,scale:1,dragX:0,dragY:0,containerSize:280,lastPinch:0};function showCropModal(id,dataUrl){const img=new Image();img.onload=function(){const nw=img.naturalWidth,nh=img.naturalHeight,csz=cropState.containerSize,fit=csz/Math.max(nw,nh);cropState.scale=Math.max(.02,Math.min(3,fit));cropState.x=-(nw*cropState.scale-csz)/2;cropState.y=-(nh*cropState.scale-csz)/2;const html=`<div id="cropContainer" class="crop-container"><img id="cropImg" class="crop-img" src="${esc(dataUrl)}"></div><button class="action-btn" onclick="confirmCrop('${id}')" style="width:100%;margin-top:10px">✅ ${t('save')}</button>`;showModal(`<h3>${t('cropAvatar')}</h3>${html}`);const c=document.getElementById('cropContainer');c.onmousedown=function(e){cropState.dragging=true;cropState.dragX=e.clientX-cropState.x;cropState.dragY=e.clientY-cropState.y;c.style.cursor='grabbing'};document.onmousemove=function(e){if(!cropState.dragging||!document.getElementById('cropContainer')){cropState.dragging=false;return}cropState.x=e.clientX-cropState.dragX;cropState.y=e.clientY-cropState.dragY;updateCropTransform()};document.onmouseup=function(){cropState.dragging=false;const el=document.getElementById('cropContainer');if(el)el.style.cursor='grab'};c.ontouchstart=function(e){e.preventDefault();if(e.touches.length===1){const t=e.touches[0];cropState.dragging=true;cropState.dragX=t.clientX-cropState.x;cropState.dragY=t.clientY-cropState.y;cropState.lastPinch=0}else if(e.touches.length===2){cropState.dragging=false;const dx=e.touches[0].clientX-e.touches[1].clientX,dy=e.touches[0].clientY-e.touches[1].clientY;cropState.lastPinch=Math.sqrt(dx*dx+dy*dy)}};c.ontouchmove=function(e){e.preventDefault();if(e.touches.length===1&&cropState.dragging){const t=e.touches[0];cropState.x=t.clientX-cropState.dragX;cropState.y=t.clientY-cropState.dragY;updateCropTransform()}else if(e.touches.length===2){const dx=e.touches[0].clientX-e.touches[1].clientX,dy=e.touches[0].clientY-e.touches[1].clientY;const dist=Math.sqrt(dx*dx+dy*dy);if(cropState.lastPinch>0){const factor=dist/cropState.lastPinch;cropState.scale=Math.max(.02,Math.min(3,cropState.scale*factor));updateCropTransform()}cropState.lastPinch=dist}};c.ontouchend=function(e){cropState.dragging=false;if(e.touches.length<2)cropState.lastPinch=0};updateCropTransform()};img.src=dataUrl}function updateCropTransform(){const el=document.getElementById('cropImg');if(!el)return;el.style.transform='translate('+cropState.x+'px,'+cropState.y+'px) scale('+cropState.scale+')'}function confirmCrop(id){const c=document.getElementById('cropContainer'),i=document.getElementById('cropImg');if(!c||!i)return;document.onmousemove=null;document.onmouseup=null;const sz=cropState.containerSize,s=cropState.scale;const cx=(sz/2-cropState.x)/s,cy=(sz/2-cropState.y)/s,r=(sz/2)/s;const canvas=document.createElement('canvas');const out=200;canvas.width=out;canvas.height=out;const ctx=canvas.getContext('2d');ctx.beginPath();ctx.arc(out/2,out/2,out/2,0,Math.PI*2);ctx.clip();ctx.drawImage(i,cx-r,cy-r,r*2,r*2,0,0,out,out);closeModal();setAvatar(id,canvas.toDataURL('image/jpeg',.8))}
function setAvatar(id,e){localStorage.setItem('avatar_'+id,e);closeModal();const p=findPeer(id);if(p){state.selectedPeer=p;renderPeer()};syncAvatarsToServer()}
