// ── notifications ──
function _addNotification(title,text){const n={id:Date.now()+'_'+Math.random().toString(36).slice(2,6),title,text,ts:Date.now(),read:false};const list=JSON.parse(localStorage.getItem('wgNotif')||'[]');list.unshift(n);localStorage.setItem('wgNotif',JSON.stringify(list))}
function _getNotifications(){return JSON.parse(localStorage.getItem('wgNotif')||'[]')}
function _unreadCount(){return _getNotifications().filter(n=>!n.read).length}
function _markRead(){const list=_getNotifications();list.forEach(n=>n.read=true);localStorage.setItem('wgNotif',JSON.stringify(list))}
function _showNotifications(){const list=_getNotifications();showModal(`<h3>🔔 ${t('notifications')}${list.filter(n=>!n.read).length?`<span style="font-size:14px;background:var(--yellow);color:#000;border-radius:50%;padding:2px 7px;margin-left:8px">${list.filter(n=>!n.read).length}</span>`:''}</h3>${list.length?list.map(n=>`<div class="info-row" style="opacity:${n.read?'.4':'1'}"><div><div>${esc(n.title)}</div><div class="info-sub">${esc(n.text)} • ${new Date(n.ts).toLocaleString(getLang()==='ru'?'ru-RU':'en-GB',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}</div></div></div>`).join(''):`<div class="muted">${t('noEvents')}</div>`}${list.some(n=>!n.read)?`<button class="primary-btn" onclick="_markRead();closeModal()">${t('markRead')}</button>`:''}`)}

// ── traffic history ──
async function openTraffic(){const p=state.selectedPeer;if(!p)return;state._trafficCache=null;try{const[daysRes,hoursRes]=await Promise.all([api('/peer/'+p.client_id+'/traffic/days'),api('/peer/'+p.client_id+'/traffic/hours')]);state._trafficDays=(await daysRes.json()).days||[];state._trafficHours=(await hoursRes.json()).hours||[]}catch(e){state._trafficDays=[];state._trafficHours=[]}renderTraffic();setScreen('screenTraffic')}
function fmtDate(d){const dd=String(d.getDate()).padStart(2,'0');const mm=String(d.getMonth()+1).padStart(2,'0');return dd+'.'+mm+'.'+d.getFullYear()}
function dayName(i){return[t('mon'),t('tue'),t('wed'),t('thu'),t('fri'),t('sat'),t('sun')][i]}
function gb(n){return (n/1073741824).toFixed(1)+' '+t('gbLabel')}
I18N.en.mbLabel=' MB';I18N.ru.mbLabel=' MB'
function mb(n){return Math.round(n/1048576)+t('mbLabel')}
function showTrafficTip(el,label,total,down,up,isHourly){const fmt=isHourly?mb:gb;document.querySelectorAll('.tip-box').forEach(e=>e.remove());const b=document.createElement('div');b.className='tip-box';b.innerHTML=`<div class="tip-row green">\u2191 ${fmt(up)}</div><div class="tip-row blue">\u2193 ${fmt(down)}</div>`;document.body.appendChild(b);const r=el.getBoundingClientRect(),br=b.getBoundingClientRect();let l=r.left+r.width/2-br.width/2;if(l<10)l=10;if(l+br.width>innerWidth-10)l=innerWidth-br.width-10;let t=r.top-br.height-8;if(t<10){t=r.bottom+8;b.classList.add('below')}b.style.left=l+'px';b.style.top=t+'px';const hnd=e=>{if(!b.contains(e.target)){b.remove();document.removeEventListener('click',hnd)}};setTimeout(()=>document.addEventListener('click',hnd),0)}
function trafficData(period){const now=new Date(),todayKey=fmtDate(now);if(state._trafficCache&&state._trafficCache._period===period&&state._trafficCache._today===todayKey&&state._trafficCache._peerId===state.selectedPeer?.client_id)return state._trafficCache.data;const p=state.selectedPeer;const days=state._trafficDays||[];let data;if(period==='day'){const hours=state._trafficHours||[];const currentHour=now.getHours();const tzOff=now.getTimezoneOffset()/-60;data=[];for(let i=0;i<=currentHour;i++){const hh=String(i).padStart(2,'0');const uh=String(((i-tzOff)%24+24)%24).padStart(2,'0');const h=hours.find(x=>x.h===uh);data.push({d:hh+':00',down:h?h.tx:0,up:h?h.rx:0})}}else if(period==='month'){data=[];const d=new Date(now);d.setDate(1);while(d<=now){const k=d.toISOString().slice(0,10);const day=days.find(x=>x.date===k);const rx=day?day.rx:0;const tx=day?day.tx:0;if(rx||tx)data.push({d:fmtDate(d),down:tx,up:rx});d.setDate(d.getDate()+1)}}else{data=[];const d=new Date(now);d.setDate(d.getDate()-6);for(let i=0;i<7;i++){const k=d.toISOString().slice(0,10);const day=days.find(x=>x.date===k);const rx=day?day.rx:0;const tx=day?day.tx:0;data.push({d:dayName(d.getDay()?d.getDay()-1:6)+' '+fmtDate(d),down:tx,up:rx});d.setDate(d.getDate()+1)}}state._trafficCache={_period:period,_today:todayKey,_peerId:state.selectedPeer?.client_id,data};return data}
function renderTraffic(){const show=state.trafficPeriod||'day';const data=trafficData(show);document.getElementById('screenTraffic').innerHTML=`<div class="details-head"><button class="back" onclick="openPeer('${esc(state.selectedPeer?.client_id)}')">‹</button><div class="title">${t('trafficHistory2')}</div></div><div class="tabs"><button class="${show==='day'?'active':''}" onclick="switchTraffic('day')">${t('day')}</button><button class="${show==='week'?'active':''}" onclick="switchTraffic('week')">${t('week')}</button><button class="${show==='month'?'active':''}" onclick="switchTraffic('month')">${t('month')}</button></div><div class="card"><div class="row"><div class="summary-value blue">↓ ${data.length?gb(data.reduce((s,x)=>s+x.down,0)):'0'}</div><div class="summary-value green">↑ ${data.length?gb(data.reduce((s,x)=>s+x.up,0)):'0'}</div></div><div class="muted" style="text-align:center;margin:10px">${data.length?esc(dateRangeText(show)):t('noData')}</div><div class="chart">${data.length?(function(){const mx=data.reduce((a,x)=>Math.max(a,x.down,x.up),0);const scale=mx?100/mx:1;return data.map(x=>{const hd=Math.min(x.down*scale,100),hu=Math.min(x.up*scale,100),val=x.down+x.up;return`<div style="flex:1" onclick="showTrafficTip(this,'${esc(x.d)}',${val},${x.down},${x.up},${show==='day'})"><div class="bar-wrap"><div class="bar" style="height:${hd}px"></div><div class="bar up" style="height:${hu}px"></div></div><div class="day-label">${x.d}</div></div>`}).join('')})():`<div class="muted" style="padding:40px;text-align:center">${t('noData')}</div>`}</div><div class="row" style="justify-content:center;gap:26px;margin-top:8px"><span class="blue">↓ ${t('download')}</span><span class="green">↑ ${t('upload')}</span></div></div><div class="card" style="max-height:300px;overflow-y:auto;-webkit-overflow-scrolling:touch">${data.length?data.map((x,i)=>{const isHourly=show==='day';return`<div class="day-row"><span>${x.d}</span><span>${isHourly?mb(x.down):gb(x.down)} <span class="blue">↓</span></span><span class="green">${isHourly?mb(x.up):gb(x.up)} ↑</span></div>`}).join(''):`<div class="muted" style="text-align:center;padding:20px">${t('noData')}</div>`}</div>`}
function switchTraffic(p){state.trafficPeriod=p;renderTraffic()}
let _eventsShowAll=false;let _gtShowAll=false;async function openGlobalTraffic(){try{const[g,h]=await Promise.all([api('/traffic/global/days').then(x=>x.json()),api('/traffic/global/hours').then(x=>x.json())]);state.globalTrafficDays=g.days||[];state.globalTrafficHours=h.hours||[]}catch(e){state.globalTrafficDays=[];state.globalTrafficHours=[]}state.globalTrafficPeriod='day';_gtShowAll=false;renderGlobalTraffic();setScreen('screenTraffic')}function switchGlobalTraffic(p){state.globalTrafficPeriod=p;_gtShowAll=false;renderGlobalTraffic()}function renderGlobalTraffic(){const period=state.globalTrafficPeriod||'day',w=(state.dashboard||{}).wireguard||{},peers=state.peers||[],days=state.globalTrafficDays||[],hours=state.globalTrafficHours||[];const now=new Date();function mondayOfWeek(d){const r=new Date(d);const dow=r.getDay();r.setDate(r.getDate()-(dow===0?6:dow-1));return r}function weekDays(d){const mon=mondayOfWeek(d);const result=[];for(let i=0;i<7;i++){const r=new Date(mon);r.setDate(mon.getDate()+i);result.push(r)}return result}const topField=period==='day'?'today_total_bytes':period==='week'?'week_total_bytes':period==='month'?'month_total_bytes':'year_total_bytes',rxField=period==='day'?'today_rx_bytes':period==='week'?'week_rx_bytes':period==='month'?'month_rx_bytes':'year_rx_bytes',txField=period==='day'?'today_tx_bytes':period==='week'?'week_tx_bytes':period==='month'?'month_tx_bytes':'year_tx_bytes',humanField=topField.replace('_bytes','_human');let totalBytes=0,rxBytes=0,txBytes=0,todayBytes=0;if(period==='week'){const wds=weekDays(now);for(const d of wds){const k=d.toISOString().slice(0,10);const dd=days.find(x=>x.date===k);rxBytes+=dd?dd.rx:0;txBytes+=dd?dd.tx:0}totalBytes=rxBytes+txBytes;for(const p of peers)todayBytes+=p.today_total_bytes||0}else{for(const p of peers){totalBytes+=p[topField]||0;rxBytes+=p[rxField]||0;txBytes+=p[txField]||0;todayBytes+=p.today_total_bytes||0}}const periodLabels={'day':t('today'),'week':t('week'),'month':t('month'),'year':t('year2')},periodLabel=periodLabels[period];const rxPct=totalBytes>0?(rxBytes/totalBytes*100):50,totalHuman=humanBytes(totalBytes),warnBytes=typeof w.traffic_warn_bytes==='number'?w.traffic_warn_bytes:32212254720,warnGb=Math.round(warnBytes/1073741824),usagePct=warnBytes?Math.min(100,Math.round(todayBytes/warnBytes*100)):0,todayHuman=humanBytes(todayBytes);let chartData;if(period==='day'){chartData=[];const tzOff=now.getTimezoneOffset()/-60;for(let i=0;i<24;i++){const hh=String(i).padStart(2,'0');const uh=String(((i-tzOff)%24+24)%24).padStart(2,'0');const h=hours.find(x=>x.h===uh);chartData.push({label:hh,rx:h?h.rx:0,tx:h?h.tx:0})}}else if(period==='week'){const wds=weekDays(now);chartData=[];for(const d of wds){const k=d.toISOString().slice(0,10);const dd=days.find(x=>x.date===k);chartData.push({label:dayName(d.getDay()?d.getDay()-1:6),rx:dd?dd.rx:0,tx:dd?dd.tx:0})}}else{const chartDays=period==='month'?30:12;chartData=[];for(let i=chartDays-1;i>=0;i--){if(period==='year'){const d=new Date(now.getFullYear(),now.getMonth()-i,1);const y=d.getFullYear(),m=d.getMonth();const monthKey=y+'-'+String(m+1).padStart(2,'0');const monthDays=days.filter(x=>x.date.startsWith(monthKey));const rx=monthDays.reduce((s,x)=>s+(x.rx||0),0);const tx=monthDays.reduce((s,x)=>s+(x.tx||0),0);chartData.push({label:monthKey.slice(5),rx,tx})}else{const d=new Date(now);d.setDate(d.getDate()-i);const key=d.toISOString().slice(0,10);const dd=days.find(x=>x.date===key);chartData.push({label:period==='month'?String(d.getDate()):'',rx:dd?dd.rx:0,tx:dd?dd.tx:0})}}}const mx=chartData.reduce((a,x)=>Math.max(a,x.rx+x.tx),0),scale=mx?100/mx:1;const sorted=[...peers].sort((a,b)=>(b[topField]||0)-(a[topField]||0)),topFieldDev=topField,humanFieldDev=humanField;const sortedDev=[...peers].sort((a,b)=>(b[topFieldDev]||0)-(a[topFieldDev]||0)),topPeers=sortedDev.filter(p=>(p[topFieldDev]||0)>0).slice(0,5),othersTotal=sortedDev.slice(5).reduce((s,p)=>s+(p[topFieldDev]||0),0),maxVal=topPeers.length?topPeers[0][topFieldDev]||1:1;function peerEmoji(p){const v=localStorage.getItem('avatar_'+p.client_id);if(v&&!v.startsWith('data:image/'))return v;return peerAvatar(p)}document.getElementById('screenTraffic').innerHTML=`
<div class="gt-head"><div class="back" onclick="showMain('home')">‹</div><h1>${esc(t('traffic'))}</h1></div>
<div class="gt-segment"><button class="${period==='day'?'active':''}" onclick="switchGlobalTraffic('day')">${esc(t('day'))}</button><button class="${period==='week'?'active':''}" onclick="switchGlobalTraffic('week')">${esc(t('week'))}</button><button class="${period==='month'?'active':''}" onclick="switchGlobalTraffic('month')">${esc(t('month'))}</button><button class="${period==='year'?'active':''}" onclick="switchGlobalTraffic('year')">${esc(t('year2'))}</button></div>
<section class="gt-summary"><div><div class="gt-label">${esc(t('totalTrafficFor'))} ${esc(periodLabel)}</div><div class="gt-big">${esc(totalHuman)}</div><div class="gt-rxtx"><div><b class="gt-tx">↓ ${esc(humanBytes(txBytes))}</b><span class="gt-label">${esc(t('downloaded'))}</span></div><div><b class="gt-rx">↑ ${esc(humanBytes(rxBytes))}</b><span class="gt-label">${esc(t('uploaded'))}</span></div></div></div><div class="gt-donut" style="background:conic-gradient(var(--green) 0 ${rxPct}%,var(--blue) ${rxPct}% 100%)"><div class="gt-donut-text">${esc(totalHuman.replace(t('gbLabel'),'').trim())}<span>${esc(t('gbLabel'))}</span></div></div></section>
${period==='day'?`<section class="card"><div class="gt-card-head"><div class="gt-card-title">${esc(t('warningThreshold'))}</div><div class="gt-link" onclick="showThresholdEdit()">${esc(t('change'))}</div></div><div>${warnGb?warnGb+" "+t('gb')+" "+t('inDay'):"—"}</div><div class="gt-progress-bg"><div class="gt-progress-fill" style="width:${usagePct}%"></div></div><div class="gt-label">${esc(t('used'))}: ${esc(todayHuman)}${warnGb?" ("+usagePct+"%)":""} ${esc(t('todayLabel'))}</div></section>`:''}
<section class="card"><div class="gt-card-head"><div class="gt-card-title">${esc(t('trafficHistory'))}</div></div><div class="gt-chart"><div class="gt-gridline gt-g1"></div><div class="gt-gridline gt-g2"></div><div class="gt-gridline gt-g3"></div>${chartData.map(x=>{const h=Math.min((x.rx+x.tx)*scale,100);return`<div class="gt-bar-wrap" onclick="showTrafficTip(this,'${esc(x.label)}',${x.rx+x.tx},${x.tx},${x.rx},${period==='day'})"><div class="gt-bar${x.isToday?' gt-today':''}" style="height:${h}px"></div><div class="gt-day"${x.isToday?' style="color:var(--blue)"':''}>${esc(x.label)}</div></div>`}).join('')}</div></section>
<section class="card"><div class="gt-card-head"><div class="gt-card-title">${esc(t('topDevices'))} ${esc(periodLabel)}</div></div>${topPeers.map(p=>{const pct=Math.round(((p[topFieldDev]||0)/maxVal)*100);return`<div class="gt-device-row"><div class="gt-dev-icon">${peerEmoji(p)}</div><div><div class="gt-dev-name">${esc(p.name)}</div><div class="gt-mini-bg"><div class="gt-mini-fill" style="width:${pct}%"></div></div></div><div class="gt-dev-val">${esc(p[humanFieldDev]||humanBytes(p[topFieldDev]||0))}</div></div>`}).join('')}${othersTotal>0?`<div class="gt-device-row"><div class="gt-dev-icon gt-other-icon">⌁</div><div><div class="gt-dev-name">${esc(t('others'))}</div><div class="gt-mini-bg"><div class="gt-mini-fill" style="width:${Math.min(100,Math.round((othersTotal/maxVal)*100))}%"></div></div></div><div class="gt-dev-val">${esc(humanBytes(othersTotal))}</div></div>`:''}</section>`;document.getElementById('screenTraffic').querySelector('.gt-chart')?.scrollTo({left:999,behavior:'smooth'})}
function showThresholdEdit(){showModal(`<h3>${esc(t('warningThreshold'))}</h3>${[5,10,25,30,50,100].map(v=>`<div class="info-row nav-row" onclick="setThreshold(${v});closeModal()"><div class="info-title">${v} ${esc(t('gb'))} ${esc(t('inDay'))}</div></div>`).join('')}<div class="info-row nav-row" onclick="setThreshold(0);closeModal()"><div class="info-title">${esc(t('disable'))}</div></div>`)}
async function setThreshold(gb){try{await api('/settings',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({traffic_warn_gb:gb})});const[d,p]=await Promise.all([api('/dashboard').then(x=>x.json()),api('/peers').then(x=>x.json())]);state.dashboard=d;state.peers=p.peers||[];renderGlobalTraffic()}catch(e){toast(t('saveError'))}}
