function openLimits(){renderLimits();setScreen('screenLimits')}
function renderLimits(){const p=state.selectedPeer,r=ruleFor(p);const dailyGb=Math.round((r.daily_bytes||0)/GB);const sched=r.schedule||{};const days=sched.days||[];const dayNames=[t('mon'),t('tue'),t('wed'),t('thu'),t('fri'),t('sat'),t('sun')];const speedVal=r.speed_limit_rate||'';document.getElementById('screenLimits').innerHTML=`<div class="details-head"><button class="back" onclick="openPeer('${esc(p.client_id)}')">‹</button><div class="title">${t('limitsAndProtection')}</div><button class="blue" onclick="saveLimits()">${t('save2')}</button></div><div class="card info-list" style="margin-top:36px"><div class="info-row nav-row" onclick="pickSpeed('${esc(p.client_id)}')"><div class="info-icon">🐢</div><div class="info-title">${t('speed')}</div><div class="info-value">${esc(speedVal||t('noLimit'))}</div><div class="chev">›</div></div><div class="info-row nav-row" onclick="pickDaily('${esc(p.client_id)}')"><div class="info-icon">◴</div><div class="info-title">${t('dailyLimit')}</div><div class="info-value">${esc(dailyGb?dailyGb+' '+t('gb'):t('noLimit2'))}</div><div class="chev">›</div></div><div class="info-row" style="border-bottom:0"><div class="info-icon">🌙</div><div class="info-title">${t('restSchedule')}</div><label class="sched-toggle${sched.enabled?' on':''}" style="margin:0"><input type="checkbox" id="schedToggle" ${sched.enabled?'checked':''} onchange="document.querySelector('.sched-toggle').classList.toggle('on',this.checked)"><span class="sched-slider"></span></label></div><div style="max-width:260px;margin:0 auto 10px"><div class="input-row"><input id="schedStart" type="time" value="${sched.start||'22:00'}"><input id="schedEnd" type="time" value="${sched.end||'07:00'}"></div></div><div style="padding:0 0 14px 43px;display:flex;gap:8px;flex-wrap:wrap">${dayNames.map((n,i)=>`<label style="display:inline-flex;align-items:center;gap:6px;font-size:13px;color:var(--muted);min-width:44px"><input type="checkbox" class="dayCb" value="${i}" ${days.includes(i)?'checked':''} style="width:18px;height:18px;margin:0">${n}</label>`).join('')}</div></div></div><div class="card form-card"><h3>${t('protection')}</h3><div class="row"><div><b>🔒 ${t('clientProtection2')}</b><div class="muted">${t('protectClientDesc')}</div></div><input id="protectToggle" type="checkbox" ${p.protected?'checked':''} style="width:24px"></div></div><div class="card danger-text" onclick="resetLimits()">${t('resetAllLimits')}</div>`}
