function pickSpeed(id){const rateVal=(ruleFor(state.selectedPeer)||{}).speed_limit_rate||'';showModal(`<h3>🐢 ${t('speed')}</h3>${['','256kbit','1mbit','5mbit'].map(v=>`<div class="info-row nav-row" onclick="setSpeed('${id}','${v}')" style="${v===rateVal?'color:var(--blue)':''}"><div class="info-title">${v?t('rate'+v):t('noLimit')}</div>${v===rateVal?'<span class="blue">✓</span>':''}</div>`).join('')}`)}
