async function setSpeed(id,rate){try{if(rate)await api(`/peer/${id}/speed-limit`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({rate})});else await api(`/peer/${id}/speed-normal`,{method:'POST'});const s=ruleFor(state.selectedPeer)||{};if(rate!==s.speed_limit_rate){await api(`/parental/rules/${id}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({enabled:!!(s.daily_bytes||rate),daily_bytes:s.daily_bytes||0,speed_limit_threshold:0,speed_limit_rate:rate||'',auto_enable:true,schedule:s.schedule||{start:'22:00',end:'07:00',days:[0,1,2,3,4,5,6],timezone_offset:new Date().getTimezoneOffset()}})});}closeModal();toast(t('saved'));await refreshAll();const _rr=await api('/parental/rules').then(x=>x.json()).catch(()=>({}));state.rules=_rr.rules||{};state.selectedPeer=findPeer(id);openLimits()}catch(e){closeModal();toast(t('saveError'))}}
function pickDaily(id){const gb=Math.round((ruleFor(state.selectedPeer)||{}).daily_bytes/GB)||0;showModal(`<h3>◴ ${t('dailyLimit')}</h3>${[0,1,5,10].map(v=>`<div class="info-row nav-row" onclick="setDaily('${id}',${v})" style="${v===gb?'color:var(--blue)':''}"><div class="info-title">${v?v+' '+t('gb'):t('noLimit2')}</div>${v===gb?'<span class="blue">✓</span>':''}</div>`).join('')}`)}
async function setDaily(id,gb){const s=ruleFor(state.selectedPeer)||{};try{await api(`/parental/rules/${id}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({enabled:!!(gb||s.speed_limit_rate),daily_bytes:gb*GB,speed_limit_threshold:0,speed_limit_rate:s.speed_limit_rate||'',auto_enable:true,schedule:s.schedule||{start:'22:00',end:'07:00',days:[0,1,2,3,4,5,6],timezone_offset:new Date().getTimezoneOffset()}})});closeModal();toast(t('saved'));await refreshAll();const _rr=await api('/parental/rules').then(x=>x.json()).catch(()=>({}));state.rules=_rr.rules||{};state.selectedPeer=findPeer(id);openLimits()}catch(e){closeModal();toast(t('saveError'))}}
async function saveLimits(){const p=state.selectedPeer;const r=ruleFor(p);const s={enabled:document.getElementById('schedToggle').checked,start:document.getElementById('schedStart').value,end:document.getElementById('schedEnd').value,days:[...document.querySelectorAll('.dayCb:checked')].map(x=>Number(x.value)),timezone_offset:new Date().getTimezoneOffset()};try{await api(`/parental/rules/${p.client_id}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({enabled:!!(r.daily_bytes||r.speed_limit_rate||s.enabled),daily_bytes:r.daily_bytes||0,speed_limit_threshold:0,speed_limit_rate:r.speed_limit_rate||'',auto_enable:true,schedule:s})});const pt=document.getElementById('protectToggle');const protected=pt?pt.checked:false;await api(`/peer/${p.client_id}/protect`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({protected})}).catch(()=>{});const peer=state.peers.find(c=>String(c.client_id)===String(p.client_id));if(peer)peer.protected=protected;toast(t('saved'));await refreshAll();const rr=await api('/parental/rules').then(x=>x.json()).catch(()=>({}));state.rules=rr.rules||{};state.selectedPeer=findPeer(p.client_id);openPeer(p.client_id)}catch(e){toast(t('saveError'))}}
async function resetLimits(){if(!await confirmAsync(t('resetConfirm')))return;const p=state.selectedPeer;await api(`/parental/rules/${p.client_id}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({enabled:false,daily_bytes:0,speed_limit_threshold:0,speed_limit_rate:'',auto_enable:true,schedule:{enabled:false,days:[],start:'22:00',end:'07:00',timezone_offset:0}})});await api(`/peer/${p.client_id}/speed-normal`,{method:'POST'}).catch(()=>{});toast(t('resetDone'));const rr=await api('/parental/rules').then(x=>x.json()).catch(()=>({}));state.rules=rr.rules||{};state.selectedPeer=findPeer(p.client_id);openPeer(p.client_id)}
