function hb(v){if(!v||v<0)return'0 B';const u=['B','KB','MB','GB','TB'];let i=0;while(v>=1024&&i<u.length-1){v/=1024;i++}return v.toFixed(1)+' '+u[i]}async function loadDiagnostics(){const el=document.getElementById('diagnosticsBody');if(!el)return;try{const d=await(await api('/diagnostics')).json();const ph=(v)=>esc(Math.round(v))+'%';const hn=(state.dashboard||{}).hostname||'';el.innerHTML=`<div class="info-list">${hn?`<div class="info-row" style="border-bottom-color:rgba(255,255,255,.04)"><span class="info-title" style="font-size:21px;font-weight:700">${serverLocation(hn)}</span></div>`:''}<div class="info-row"><span class="info-icon">🖥️</span><span class="info-title">CPU</span><span class="info-value">${ph(d.cpu_pct)}</span><div class="bar"><div class="fill" style="width:${Math.min(d.cpu_pct,100)}%"></div></div></div><div class="info-row"><span class="info-icon">🧠</span><span class="info-title">RAM</span><span class="info-value">${ph(d.mem_pct)}</span><div class="bar"><div class="fill" style="width:${Math.min(d.mem_pct,100)}%"></div></div></div><div class="info-row"><span class="info-icon">💾</span><span class="info-title">${t('disk')}</span><span class="info-value">${ph(d.disk_pct)}</span><div class="bar"><div class="fill" style="width:${Math.min(d.disk_pct,100)}%"></div></div></div><div class="info-row"><span class="info-icon">${({wg:'🌐',awg:'🌍',xray:'🔒'})[state.dashboard?.variant]||'🌐'}</span><div style="flex:1"><span class="info-title">${({wg:'WireGuard',awg:'AmneziaWG',xray:'Xray (VLESS)'})[state.dashboard?.variant]||'WireGuard'}</span>${state.dashboard?.variant==='xray'?`<div class="info-sub" style="font-size:12px">🔒 REALITY :443 / 🌀 WS :8444 / 🌐 XHTTP :8445</div>`:''}</div><span class="info-value ${d.checks.wg==='ok'?'green':'warn'}">${d.checks.wg==='ok'?t('healthWorking'):t('healthError')}</span></div></div>`}catch(e){el.innerHTML=`<span class="warn">⚠</span> ${esc(e.message)}`}}
