function backupTime(ts){if(!ts)return t('noData');try{return new Date(ts*1000).toLocaleString([],{year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'})}catch(e){return String(ts)}}
function renderBackupInfo(item,title,kind){if(!item||!item.exists){return`<div class="backup-item"><div class="backup-item-main"><div><b>${title}</b></div><div class="meta">${t('none')}</div></div></div>`}return`<div class="backup-item"><div class="backup-item-main"><div><b>${title}</b></div><div>${backupTime(item.mtime)}</div><div class="meta">${t('size')}: ${esc(item.size_human||'')}</div></div><div style="display:flex;flex-direction:column;gap:8px;align-items:flex-end"><button class="backup-download-btn" onclick="downloadBackup('${kind}')">${t('download')}</button><button class="backup-download-btn" onclick="restoreBackup('${kind}')">${t('restore2')}</button></div></div>`}
async function loadBackupStatus(){const el=document.getElementById('backupStatus');if(!el)return;if(cachedBackupStatus){el.innerHTML=cachedBackupStatus;return}el.innerHTML=`<div class="backup-placeholder">${t('loading')}</div>`;try{const res=await api('/backup/status?_='+Date.now());const data=await res.json();cachedBackupStatus=`<div class="card">${renderBackupInfo(data.latest,t('latestBackup'),'latest')}</div><div class="card">${renderBackupInfo(data.previous,t('previousBackup'),'previous')}</div>`;el.innerHTML=cachedBackupStatus}catch(e){el.innerHTML=t('backupLoadFailed')}}
async function createBackupNow(){try{toast(t('backupCreating'));await syncAvatarsToServer();const r=await(await api('/backup/create',{method:'POST'})).json();if(r.created===false){toast(r.message||t('backupCreateFailed'));return}cachedBackupStatus=null;toast(t('backupCreated'));refreshAll();loadBackupStatus()}catch(e){toast(t('backupCreateFailed'))}}
async function downloadBackup(kind){const token=getToken();if(!token)return showLoginOverlay();try{const r=await fetch('/backup/download/'+kind+'?token='+encodeURIComponent(token)+'&t='+Date.now());if(!r.ok)return;const blob=await r.blob();const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;const cd=r.headers.get('Content-Disposition')||'';const m=cd.match(/filename="(.+?)"/);a.download=m?m[1]:kind+'.wgadmin';a.style.display='none';document.body.appendChild(a);a.click();setTimeout(()=>{a.remove();URL.revokeObjectURL(url)},5e3)}catch(e){}}
async function restoreBackup(kind){if(!await confirmAsync(t('restoreConfirm')))return;try{toast(t('restoreStarted'));const r=await(await api('/backup/restore/'+kind,{method:'POST'})).json();if(r.ok===false){toast(r.message||t('restoreFailed'));return}let s=5;(function tick(){toast(t('restoreCountdown').replace('{n}',s));if(s<=0){location.reload();return}s--;setTimeout(tick,1000)})()}catch(e){toast(t('restoreFailed'))}}

// ── maintenance ──
function maintenanceMessage(path){if(path.includes('restart-vpn'))return t('msgRestartVpn');if(path.includes('restart-admin'))return t('msgRestartAdmin');if(path.includes('reboot-server'))return t('msgRebootVps');return t('msgOk')}
async function maintenancePost(path,msg){if(!await confirmAsync(msg))return;const okMsg=maintenanceMessage(path);toast(okMsg);const waitMs=path.includes('reboot-server')?120000:25000;setTimeout(()=>{refreshAll()},waitMs);try{await api(path,{method:'POST'})}catch(e){toast(t('saveError'))}}
function restartVpn(){maintenancePost('/maintenance/restart-vpn',t('confirmRestartVpn'))}
function restartAdmin(){maintenancePost('/maintenance/restart-admin',t('confirmRestartAdmin'))}
function rebootServer(){maintenancePost('/maintenance/reboot-server',t('confirmRebootVps'))}
// ── security: tokens ──
async function loadTokenList(){const container=document.getElementById('tokenList');if(!container)return;try{const res=await(await api('/tokens?_='+Date.now())).json();if(!res.length){container.innerHTML=`<p class="muted">${t('noTokens')}</p>`;return}container.innerHTML=res.map(tok=>`<div class="token-row"><div class="token-info"><div class="token-label">${esc(tok.label)}</div><div class="token-prefix">${esc(tok.prefix)}</div></div><button class="danger small" onclick="revokeToken('${escapeAttr(tok.id)}','${escapeAttr(tok.label)}')">${t('revoke')}</button></div>`).join('')}catch(e){container.innerHTML=`<p class="muted">${t('noTokens')}</p>`}}
function showCreateToken(){showModal(`<h3>🔑 ${t('createToken')}</h3><input id="newTokenName" type="text" placeholder="${t('tokenNamePlaceholder')}"><input id="newTokenPass" type="text" inputmode="text" placeholder="${t('enterToken')}" style="margin-top:8px"><div class="modal-actions"><button onclick="closeModal()">${t('cancel')}</button><button class="primary-btn" onclick="createToken()">${t('create2')}</button></div>`);setTimeout(()=>document.getElementById('newTokenName')?.focus(),100)}
async function createToken(){const input=document.getElementById('newTokenName');const label=input?input.value.trim():'';if(!label){toast(t('tokenNameRequired'));return}const passInput=document.getElementById('newTokenPass');const password=passInput?passInput.value.trim():'';if(!password){toast(t('enterToken'));return}try{const res=await(await api('/tokens',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({label,password})})).json();closeModal();const newToken=res.token;localStorage.setItem('wgApiToken',newToken);showModal(`<h3 style="margin:0 0 8px 0">🔑 ${esc(label)}</h3><p class="muted">${t('tokenCreatedHint')}</p>`);loadTokenList()}catch(e){toast(t('saveError'))}}
async function revokeToken(id,label){if(!await confirmAsync(t('confirmRevokeToken').replace('{label}',label)))return;try{await api('/tokens/'+id,{method:'DELETE'});toast('🗑 '+label);loadTokenList()}catch(e){const msg=e.message||'';if(msg.includes('current session token'))toast('⚠️ '+t('cannotRevokeCurrent'));else toast(t('saveError'))}}
function shareTokenText(token){closeModal();if(/iPad|iPhone|iPod/.test(navigator.userAgent)&&!window.MSStream){const a=document.createElement('a');a.href='data:text/plain;charset=utf-8,'+encodeURIComponent(token);a.download='vpn-api-token.txt';document.body.appendChild(a);a.click();document.body.removeChild(a);return}if(navigator.share){navigator.share({text:token}).catch(()=>{});return}const blob=new Blob([token],{type:'text/plain'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='vpn-api-token.txt';document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url)}

// ── security: protection ──
// ── modals ──
function showModal(html){document.getElementById('modalContent').innerHTML=`<div style="display:flex;justify-content:flex-end;margin-bottom:8px"><button onclick="closeModal()" style="font-size:24px;line-height:1;color:var(--muted);width:44px;height:44px;display:grid;place-items:center;border-radius:50%">×</button></div>`+html;document.getElementById('modal').showModal()}
function closeModal(){const el=document.getElementById('modal');el.close();el.onclick=null;document.getElementById('modalContent').innerHTML='';document.onmousemove=null;document.onmouseup=null}
function confirmAsync(msg){return new Promise(r=>{let done;const resolveOnce=function(v){if(resolveOnce._done)return;resolveOnce._done=true;r(v)};const mc=document.getElementById('modalContent');mc.innerHTML=`<div style="display:flex;justify-content:flex-end;margin-bottom:8px"><button onclick="closeModal()" style="font-size:24px;line-height:1;color:var(--muted);width:44px;height:44px;display:grid;place-items:center;border-radius:50%">×</button></div><p style="font-size:17px;line-height:1.5;margin:0">${esc(msg)}</p><div class="modal-actions"><button id="confirmYes" class="primary-btn">${t('confirm')}</button><button id="confirmNo">${t('cancel')}</button></div>`;const m=document.getElementById('modal');m.addEventListener('close',function(){resolveOnce(false)},{once:true});m.showModal();document.getElementById('confirmYes').onclick=function(){closeModal();setTimeout(()=>resolveOnce(true),10)};document.getElementById('confirmNo').onclick=function(){closeModal();setTimeout(()=>resolveOnce(false),10)};m.onclick=function(e){if(e.target===m)closeModal()}})}

// ── xray links ──
async function getXrayLinks(){try{const res=await api('/xray/links');return await res.json()}catch(e){toast(t('saveError'));return null}}
async function showXrayQR(proto,id,name){try{const[linkResp,qrResp]=await Promise.all([api('/peer/'+id+'/config?proto='+proto),api('/peer/'+id+'/qr?proto='+proto)]);const link=await linkResp.text();const blob=await qrResp.blob();const url=URL.createObjectURL(blob);showModal(`<h3>${proto.toUpperCase()}: ${esc(name)}</h3><div style="word-break:break-all;font-size:12px;margin:8px 0;padding:8px;background:var(--bg2);border-radius:8px">${esc(link)}</div><img src="${url}" style="width:100%;border-radius:16px;background:white;padding:10px"><div class="modal-actions"><button onclick="copyText('${escapeAttr(link)}')">📋</button><button onclick="closeModal()">${t('close2')}</button></div>`)}catch(e){toast(t('saveError'))}}
async function downloadXrayConfig(proto,id,name){const token=getToken();if(!token)return showLoginOverlay();try{const res=await api('/peer/'+id+'/config?proto='+proto);const blob=await res.blob();const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=name+'-'+proto+'.txt';document.body.appendChild(a);a.click();document.body.removeChild(a);setTimeout(()=>URL.revokeObjectURL(url),5000)}catch(e){toast(t('saveError'))}}
function copyText(txt){navigator.clipboard.writeText(txt).then(()=>toast('✓')).catch(()=>{const ta=document.createElement('textarea');ta.value=txt;document.body.appendChild(ta);ta.select();document.execCommand('copy');document.body.removeChild(ta);toast('✓')})}

// ── peer actions ──
function showCreateClient(){showModal(`<h3>${t('newDevice')}</h3><input id="newClientName" placeholder="${t('clientName')}"><div class="modal-actions"><button onclick="closeModal()">${t('cancel')}</button><button class="primary-btn" onclick="createClient()">${t('create2')}</button></div>`)}
async function createClient(){const name=document.getElementById('newClientName').value.trim();if(!name)return toast(t('invalidName'));if(!/^[\w\s\-.\u0400-\u04FF]+$/.test(name))return toast(t('invalidName'));try{const j=await(await api('/peer/create',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name})})).json();closeModal();toast(t('created'));state.peers.push({name:j.peer||name,client_id:j.client_id,ip:j.ip,enabled:true,online:false});showMain(state.currentTab||'home');refreshAll()}catch(e){toast(e.message||t('saveError'))}}
