async function showQR(id,name){try{const blob=await(await api('/peer/'+id+'/qr')).blob();const url=URL.createObjectURL(blob);showModal(`<h3>${t('qrTitle').replace('{name}',esc(name))}</h3><img src="${url}" style="width:100%;border-radius:16px;background:white;padding:10px"><div class="modal-actions"><button onclick="closeModal()">${t('close2')}</button></div>`)}catch(e){toast(t('saveError'))}}
async function downloadConfig(id,name){const token=getToken();if(!token)return showLoginOverlay();try{const res=await api('/peer/'+id+'/config');const blob=await res.blob();const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=name+'.conf';document.body.appendChild(a);a.click();document.body.removeChild(a);setTimeout(()=>URL.revokeObjectURL(url),5000)}catch(e){toast(t('saveError'))}}

async function enablePeer(id,name){try{await api('/peer/'+id+'/enable',{method:'POST'});state.peers.forEach(p=>{if(String(p.client_id)===String(id))p.enabled=true});const peer=findPeer(id);if(peer)state.selectedPeer=peer;toast(t('enable'));await refreshAll();state.selectedPeer=findPeer(id);if(state.selectedPeer)renderPeer();else showMain('devices')}catch(e){toast(t('saveError'))}}
async function disablePeer(id,name){try{await api('/peer/'+id+'/disable',{method:'POST'});state.peers.forEach(p=>{if(String(p.client_id)===String(id))p.enabled=false});const peer=findPeer(id);if(peer)state.selectedPeer=peer;toast(t('peerDisabled'));await refreshAll();state.selectedPeer=findPeer(id);if(state.selectedPeer)renderPeer();else showMain('devices')}catch(e){if(e.message.includes('Protected'))toast(t('peerProtected'));else toast(t('saveError'))}}
async function deletePeer(id,name){if(!await confirmAsync(t('confirmDeletePeer').replace('{name}',name)))return;try{await api('/peer/'+id,{method:'DELETE'});state.peers=state.peers.filter(p=>String(p.client_id)!==String(id));toast(t('deletePeer'));showMain('devices');await refreshAll()}catch(e){if(e.message.includes('Protected'))toast(t('peerProtected'));else toast(t('saveError'))}}
function editPeerName(id,oldName){showModal(`<h3>✏️ ${t('rename')}</h3><input id="renameInput" placeholder="${t('clientName')}" value="${esc(oldName)}"><div class="modal-actions"><button onclick="closeModal()">${t('cancel')}</button><button class="primary-btn" onclick="renamePeer('${esc(id)}')">${t('save')}</button></div>`);setTimeout(()=>{const el=document.getElementById('renameInput');if(el){el.focus();el.setSelectionRange(el.value.length,el.value.length)}},100)}
async function renamePeer(id){const name=document.getElementById('renameInput').value.trim();if(!name||name===state.selectedPeer?.name)return closeModal();if(!/^[\w\s\-.\u0400-\u04FF]+$/.test(name))return toast(t('invalidName'));try{await api('/peer/'+id+'/name',{method:'POST',body:JSON.stringify({name}),headers:{'Content-Type':'application/json'}});toast(t('saved'));await refreshAll();state.selectedPeer=findPeer(id);renderPeer();closeModal()}catch(e){toast(t('saveError'))}}
async function toggleRole(id,name,newRole){const label=newRole==='admin'?t('admin'):t('user');if(!await confirmAsync(t('roleChangeConfirm').replace('{role}',label).replace('{name}',name)))return;try{await api('/peer/'+id+'/role',{method:'POST',body:JSON.stringify({role:newRole}),headers:{'Content-Type':'application/json'}});toast(t('saved'));await refreshAll();if(state.settingsPage==='access')renderSettingsAccess()}catch(e){toast(t('saveError'))}}

// ── refresh ──
let _refreshPromise=null;async function refreshAll(){while(_refreshPromise){await _refreshPromise;}_refreshPromise=(async()=>{try{const onDetail=['screenPeer','screenTraffic','screenLimits','screenSettings'].some(id=>document.getElementById(id)?.classList.contains('active'));if(onDetail){const p=await(await api('/peers')).json();state.peers=p.peers||[];if(document.getElementById('screenPeer')?.classList.contains('active')&&state.selectedPeer){state.selectedPeer=findPeer(state.selectedPeer.client_id);if(state.selectedPeer)renderPeer()}return}const[d,p,r,a,b]=await Promise.all([api('/dashboard').then(x=>x.json()),api('/peers').then(x=>x.json()),api('/parental/rules').then(x=>x.json()).catch(()=>({rules:{}})),api('/activity').then(x=>x.json()).catch(()=>({events:[]})),api('/backup/status?_='+Date.now()).then(x=>x.json()).catch(()=>null)]);state.dashboard=d;state.peers=p.peers||[];state.rules=r.rules||{};state.activity=a.events||[];state.backups=b;cachedBackupStatus=null;if(!onDetail)showMain(state.currentTab||'home')}catch(e){renderError(e)}finally{_refreshPromise=null}})();return _refreshPromise}

// ── upload backup handler ──
document.addEventListener('change',async function(e){if(e.target.id!=='backupFileInput')return;const file=e.target.files?.[0];if(!file)return;if(!await confirmAsync(t('uploadConfirm')))return;try{toast(t('uploading'));const fd=new FormData();fd.append('file',file);const res=await(await api('/backup/upload',{method:'POST',body:fd})).json();if(res.ok===false){toast(res.message||t('restoreFailed'));return}toast(res.message||'Restored');let s=5;(function tick(){toast(t('restoreCountdown').replace('{n}',s));if(s<=0){location.reload();return}s--;setTimeout(tick,1000)})()}catch(e){toast(t('restoreFailed'))}})

// ── swipe navigation ──
let _sx=0;document.body.addEventListener('touchstart',e=>{_sx=e.touches[0].clientX},{passive:true});document.body.addEventListener('touchend',e=>{const dx=e.changedTouches[0].clientX-_sx;if(Math.abs(dx)>80){let el=e.target;while(el){if(el.scrollWidth>el.clientWidth)return;el=el.parentElement}const id=document.querySelector('.screen.active')?.id;if(id==='screenSettings'&&state.settingsPage){showSettingsPage();return}if(dx>80){if(id==='screenPeer')showMain('devices');else if(id==='screenTraffic')showMain('home');else if(id==='screenLimits')showMain('home');else if(id==='screenSettings')showMain('devices');else if(id==='screenDevices')showMain('home')}else{if(id==='screenHome')showMain('devices');else if(id==='screenDevices')showMain('settings');else if(id==='screenTraffic')showMain('home');else if(id==='screenSettings')showMain('home')}}},{passive:true})

// ── pull-to-refresh ──
let _pullY=0,_pullRefreshing=false;document.body.addEventListener('touchstart',e=>{_pullY=e.touches[0].clientY},{passive:true});document.body.addEventListener('touchmove',e=>{if(_pullRefreshing)return;const dy=e.touches[0].clientY-_pullY;if(dy>50&&document.scrollingElement.scrollTop===0){_pullRefreshing=true;refreshAll();setTimeout(()=>{_pullRefreshing=false},2000)}},{passive:true})
// ── sw ──
if('serviceWorker'in navigator){navigator.serviceWorker.getRegistrations().then(rs=>rs.forEach(reg=>reg.unregister().catch(()=>{})));navigator.serviceWorker.register('/sw.js')}
// ── init (DOM is guaranteed ready since app.js loads at end of body) ──
document.getElementById('modal')?.addEventListener('click',e=>{if(e.target.id==='modal')closeModal()});applyLang();loadAvatarsFromServer();showMain('home');refreshAll();setInterval(()=>{if(!document.hidden)refreshAll()},5000);const sp=document.getElementById('splash');if(sp){setTimeout(()=>{sp.style.opacity='0';document.querySelector('main').style.opacity='1';document.querySelector('nav').style.opacity='1'},1500);setTimeout(()=>sp.remove(),1800)}

